/**
 * Compiled AMD build of inline_grader.js for datafield_gradeentry.
 *
 * @module     datafield_gradeentry/inline_grader
 * @copyright  2025 onwards, Australian developers
 * @license    https://www.gnu.org/licenses/gpl-3.0.html GNU GPL v3 or later
 */
define(
    ['core/ajax', 'core/notification', 'core/str'],
    function(Ajax, Notification, Str) {

    var DEBOUNCE_MS = 800;
    var debounceTimers = {};

    var init = function(cmid, contextid) { // eslint-disable-line no-unused-vars
        Str.get_strings([
            {key: 'savinggrade',     component: 'datafield_gradeentry'},
            {key: 'graded',          component: 'datafield_gradeentry'},
            {key: 'errorsavegrade',  component: 'datafield_gradeentry'},
            {key: 'gradingprogress', component: 'datafield_gradeentry'},
            {key: 'savingstatus',    component: 'datafield_gradeentry'},
            {key: 'errorsavestatus', component: 'datafield_gradeentry'},
        ]).then(function(strings) {
            var savingStr       = strings[0];
            var gradedStr       = strings[1];
            var errorStr        = strings[2];
            // strings[3] = gradingprogress (used server-side only on initial render).
            var savingStatusStr = strings[4];
            var errorStatusStr  = strings[5];

            wireGradeInputs(cmid, savingStr, gradedStr, errorStr);
            wireFeedbackAreas(cmid, savingStr, gradedStr, errorStr);
            wireReleaseControls(cmid);
            wireReleaseAllButton(cmid);
            wireSubmissionStatusButtons(cmid, savingStatusStr, errorStatusStr);
            wireResubmissionControls(cmid);
            wireRubricPanels(cmid, savingStr, gradedStr, errorStr);
            return;
        }).catch(Notification.exception);
    };

    // -------------------------------------------------------------------------
    // Grade inputs (numeric and scale select)
    // -------------------------------------------------------------------------

    var wireGradeInputs = function(cmid, savingStr, gradedStr, errorStr) {
        document.querySelectorAll('[data-gradeentry-field]:not([type="hidden"])').forEach(function(input) {
            var method = input.dataset.gradingMethod || 'numeric';
            if (method === 'rubric') {
                return;
            }

            var saveHandler = function() {
                if (input.value === '') {
                    return;
                }
                var feedback = getFeedbackFor(input.dataset.recordid);
                triggerSave(cmid, input, input.dataset.fieldid, parseFloat(input.value), feedback, '', savingStr, gradedStr, errorStr);
            };

            if (input.tagName === 'SELECT') {
                input.addEventListener('change', saveHandler);
            } else {
                input.addEventListener('input', function() {
                    var recordid = parseInt(input.dataset.recordid, 10);
                    clearTimeout(debounceTimers[recordid]);
                    debounceTimers[recordid] = setTimeout(saveHandler, DEBOUNCE_MS);
                });
                input.addEventListener('blur', function() {
                    var recordid = parseInt(input.dataset.recordid, 10);
                    clearTimeout(debounceTimers[recordid]);
                    saveHandler();
                });
            }
        });
    };

    var wireFeedbackAreas = function(cmid, savingStr, gradedStr, errorStr) {
        document.querySelectorAll('[data-gradeentry-feedback]').forEach(function(textarea) {
            textarea.addEventListener('blur', function() {
                var gradeInput = getGradeInputFor(textarea.dataset.recordid);
                if (!gradeInput || gradeInput.value === '') {
                    return;
                }
                triggerSave(
                    cmid, gradeInput, gradeInput.dataset.fieldid,
                    parseFloat(gradeInput.value), textarea.value,
                    '', savingStr, gradedStr, errorStr
                );
            });
        });
    };

    // -------------------------------------------------------------------------
    // Release controls
    // -------------------------------------------------------------------------

    var wireReleaseControls = function(cmid) {
        document.querySelectorAll('[data-gradeentry-release]').forEach(function(checkbox) {
            checkbox.addEventListener('change', function() {
                var recordid = parseInt(checkbox.dataset.recordid, 10);
                var desired  = checkbox.checked;
                Ajax.call([{
                    methodname: 'datafield_gradeentry_release_grades',
                    args: {cmid: cmid, recordids: [recordid], released: desired},
                    done: function() {
                        updateReleasedLabel(checkbox, desired);
                    },
                    fail: function(ex) {
                        checkbox.checked = !desired;
                        Notification.exception(ex);
                    },
                }]);
            });
        });
    };

    var wireReleaseAllButton = function(cmid) {
        var btn = document.getElementById('datafield-gradeentry-release-all');
        if (!btn) {
            return;
        }
        btn.addEventListener('click', function() {
            btn.disabled = true;
            Ajax.call([{
                methodname: 'datafield_gradeentry_release_grades',
                args: {cmid: cmid, recordids: [], released: true},
                done: function(result) {
                    btn.disabled = false;
                    document.querySelectorAll('[data-gradeentry-release]').forEach(function(cb) {
                        cb.checked = true;
                        updateReleasedLabel(cb, true);
                    });
                    var progressText = document.getElementById('datafield-gradeentry-progress-text');
                    if (progressText) {
                        var original = progressText.textContent;
                        progressText.textContent = result.released + ' grades released';
                        setTimeout(function() {
                            progressText.textContent = original;
                        }, 3000);
                    }
                },
                fail: function(ex) {
                    btn.disabled = false;
                    Notification.exception(ex);
                },
            }]);
        });
    };

    // -------------------------------------------------------------------------
    // Submission status buttons (student draft / submit)
    // -------------------------------------------------------------------------

    var wireSubmissionStatusButtons = function(cmid, savingStatusStr, errorStatusStr) {
        document.querySelectorAll('[data-gradeentry-submit-status]').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var recordid = parseInt(btn.dataset.recordid, 10);
                var status   = btn.dataset.status;
                var badge    = getSubmissionBadge(recordid);

                if (badge) {
                    badge.textContent = savingStatusStr;
                }

                Ajax.call([{
                    methodname: 'datafield_gradeentry_save_submission_status',
                    args: {cmid: cmid, recordid: recordid, status: status},
                    done: function(result) {
                        updateSubmissionBadge(recordid, result.status);
                    },
                    fail: function(ex) {
                        if (badge) {
                            badge.textContent = errorStatusStr;
                        }
                        Notification.exception(ex);
                    },
                }]);
            });
        });
    };

    // -------------------------------------------------------------------------
    // Require resubmission controls (teacher)
    // -------------------------------------------------------------------------

    var wireResubmissionControls = function(cmid) {
        document.querySelectorAll('[data-gradeentry-resubmit]').forEach(function(checkbox) {
            checkbox.addEventListener('change', function() {
                var recordid = parseInt(checkbox.dataset.recordid, 10);
                var desired  = checkbox.checked;

                Ajax.call([{
                    methodname: 'datafield_gradeentry_require_resubmission',
                    args: {cmid: cmid, recordid: recordid, require: desired},
                    done: function() {
                        updateSubmissionBadge(recordid, desired ? 'resubmit' : 'submitted');
                    },
                    fail: function(ex) {
                        checkbox.checked = !desired;
                        Notification.exception(ex);
                    },
                }]);
            });
        });
    };

    // -------------------------------------------------------------------------
    // Rubric panels
    // -------------------------------------------------------------------------

    var wireRubricPanels = function(cmid, savingStr, gradedStr, errorStr) {
        document.querySelectorAll('[data-gradeentry-rubric]').forEach(function(panel) {
            var recordid = parseInt(panel.dataset.recordid, 10);
            var fieldid  = parseInt(panel.dataset.fieldid, 10);
            var hidden   = panel.querySelector('[data-gradeentry-field][type="hidden"]');

            panel.querySelectorAll('.gradeentry-criterion').forEach(function(criterion) {
                criterion.querySelectorAll('.gradeentry-rubric-level').forEach(function(levelBtn) {
                    levelBtn.addEventListener('click', function() {
                        criterion.querySelectorAll('.gradeentry-rubric-level').forEach(function(b) {
                            b.classList.remove('btn-primary', 'active');
                            b.classList.add('btn-outline-secondary');
                        });
                        levelBtn.classList.remove('btn-outline-secondary');
                        levelBtn.classList.add('btn-primary', 'active');

                        var rubric   = calcRubricTotal(panel);
                        if (hidden) {
                            hidden.value = rubric.total;
                        }

                        var totalEl = panel.querySelector('.gradeentry-rubric-total');
                        if (totalEl) {
                            totalEl.textContent = totalEl.textContent.replace(/[\d.]+/, rubric.total);
                        }

                        var feedback = getFeedbackFor(recordid);
                        triggerSave(
                            cmid, hidden, fieldid, rubric.total, feedback,
                            JSON.stringify(rubric.scores),
                            savingStr, gradedStr, errorStr
                        );
                    });
                });
            });
        });
    };

    var calcRubricTotal = function(panel) {
        var total  = 0;
        var scores = [];
        panel.querySelectorAll('.gradeentry-criterion').forEach(function(criterion) {
            var selected = criterion.querySelector('.gradeentry-rubric-level.active');
            var score    = selected ? parseFloat(selected.dataset.score) : 0;
            total += score;
            scores.push(score);
        });
        return {total: total, scores: scores};
    };

    // -------------------------------------------------------------------------
    // Core save call
    // -------------------------------------------------------------------------

    var triggerSave = function(cmid, gradeInput, fieldid, gradeValue, feedback, rubricscores, savingStr, gradedStr, errorStr) {
        var recordid = parseInt(gradeInput.dataset.recordid, 10);
        var status   = getStatusFor(recordid);

        setStatus(status, 'saving', savingStr);

        Ajax.call([{
            methodname: 'datafield_gradeentry_save_grade',
            args: {
                cmid: cmid,
                recordid: recordid,
                fieldid: parseInt(fieldid, 10),
                grade: gradeValue,
                feedback: feedback || '',
                rubricscores: rubricscores || '',
            },
            done: function(result) {
                setStatus(status, 'saved', gradedStr);
                updateProgressBar(result.graded, result.total);
            },
            fail: function(ex) {
                setStatus(status, 'error', errorStr);
                Notification.exception(ex);
            },
        }]);
    };

    // -------------------------------------------------------------------------
    // DOM helpers
    // -------------------------------------------------------------------------

    var getGradeInputFor = function(recordid) {
        return document.querySelector('[data-gradeentry-field][data-recordid="' + recordid + '"]:not([type="hidden"])');
    };

    var getFeedbackFor = function(recordid) {
        var el = document.querySelector('[data-gradeentry-feedback][data-recordid="' + recordid + '"]');
        return el ? el.value : '';
    };

    var getStatusFor = function(recordid) {
        return document.querySelector('[data-gradeentry-status][data-recordid="' + recordid + '"]');
    };

    var getSubmissionBadge = function(recordid) {
        return document.querySelector('[data-gradeentry-submission-badge][data-recordid="' + recordid + '"]');
    };

    var setStatus = function(el, state, text) {
        if (!el) {
            return;
        }
        el.textContent = text;
        el.className   = 'gradeentry-status gradeentry-status--' + state;
    };

    var updateReleasedLabel = function(checkbox, isReleased) {
        var group = checkbox.closest('.gradeentry-release-group');
        var label = group ? group.querySelector('.gradeentry-release-label') : null;
        if (!label) {
            return;
        }
        label.textContent = isReleased ? label.dataset.releasedText : label.dataset.unreleasedText;
    };

    var updateProgressBar = function(graded, total) {
        var bar = document.getElementById('datafield-gradeentry-progress');
        if (!bar) {
            return;
        }
        bar.dataset.graded = graded;
        bar.dataset.total  = total;

        var text = document.getElementById('datafield-gradeentry-progress-text');
        if (text) {
            text.textContent = text.textContent.replace(/\d+\s*\/\s*\d+/, graded + ' / ' + total);
        }
    };

    var STATUS_LABELS = {
        notsubmitted: 'Not submitted',
        draft: 'Draft',
        submitted: 'Submitted for grading',
        resubmit: 'Resubmission required',
    };

    var updateSubmissionBadge = function(recordid, status) {
        var badge = getSubmissionBadge(recordid);
        if (!badge) {
            return;
        }
        badge.textContent = STATUS_LABELS[status] || status;

        badge.classList.remove('text-bg-secondary', 'text-bg-warning', 'text-bg-success', 'text-bg-danger');
        var colourMap = {
            notsubmitted: 'text-bg-secondary',
            draft: 'text-bg-warning',
            submitted: 'text-bg-success',
            resubmit: 'text-bg-danger',
        };
        badge.classList.add(colourMap[status] || 'text-bg-secondary');
    };

    return {
        init: init,
    };
});
